import{_ as s,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"101. Designated Work Groups","description":"","frontmatter":{"title":"101. Designated Work Groups","eba":"Nurses and Midwives 2024-2028","topics":["consultation","union-matters","ohs"]},"headers":[],"relativePath":"ebas/nurses-midwives/ohs/101-designated-work-groups.md","filePath":"ebas/nurses-midwives/ohs/101-designated-work-groups.md"}'),a={name:"ebas/nurses-midwives/ohs/101-designated-work-groups.md"};function r(i,e,d,p,c,g){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_101-designated-work-groups" tabindex="-1">101. Designated Work Groups <a class="header-anchor" href="#_101-designated-work-groups" aria-label="Permalink to &quot;101. Designated Work Groups&quot;">​</a></h1><p><strong>101.1</strong> Where Union members constitute the majority of the workforce within a designated work group, the Employer will establish and maintain a system of DWGs in consultation with Employees and the Unions.</p><p><strong>101.2</strong> In determining the particulars of DWGs (including number of HSRs), the following considerations will, where practicable, be taken into account:</p><p><strong>(a)</strong> the specific needs, conditions and hazards affecting employees in the area(s) concerned;</p><p><strong>(b)</strong> the working arrangements, including shiftwork, of employees in the area(s) concerned;</p><p><strong>(c)</strong> the accessibility of health and safety representatives to employees in the area(s) concerned; and</p><p><strong>(d)</strong> the geographical layout of the workplace.</p><p>Plain language terms: DWG, HSR area.</p>',8)])])}const u=s(a,[["render",r]]);export{h as __pageData,u as default};
